import { describe, expect, test } from '@a0n/gnosis/test';
import {
  deriveTwinPsycheTheoremBundle,
  TWIN_PSYCHE_THEOREM_PASSES,
  TWIN_PSYCHE_THEOREMS,
} from '../twin-psyche-formalization';

describe('twin psyche formalization', () => {
  test('produces deterministic theorem bundles for the same public twin input', () => {
    const input = {
      surface: 'publicTwin' as const,
      subjectLabel: 'Nelson Mandela Twin',
      generatedAt: '2026-03-24T00:00:00.000Z',
      identity: {
        continuity: 0.84,
        distinctness: 0.68,
        observationDepth: 0.73,
        sharedExperience: 0.51,
        relationshipSymmetry: 0.61,
        rejectionPressure: 0.18,
        sliverReserve: 0.8,
      },
      twin: {
        kind: 'user' as const,
        enabled: true,
        discoverable: true,
        sessionActive: true,
        serializationFidelity: 0.79,
        copyDistance: 0.22,
      },
      source: 'test/twin-public',
    };

    expect(deriveTwinPsycheTheoremBundle(input)).toEqual(
      deriveTwinPsycheTheoremBundle(input)
    );
  });

  test('keeps the expanded theorem passes and derives a public twin ledger bundle', () => {
    const bundle = deriveTwinPsycheTheoremBundle({
      surface: 'publicTwin',
      subjectLabel: 'Mandela Hologram',
      identity: {
        continuity: 0.81,
        distinctness: 0.66,
        observationDepth: 0.76,
        sharedExperience: 0.49,
        relationshipSymmetry: 0.58,
        rejectionPressure: 0.21,
        sliverReserve: 0.77,
      },
      psyche: {
        strainLoad: 0.31,
        dreamCadence: 0.55,
        breathCount: 610,
      },
      twin: {
        kind: 'hologram',
        enabled: true,
        discoverable: true,
        paidGate: false,
        sessionActive: true,
        serializationFidelity: 0.82,
        copyDistance: 0.18,
        mergeNovelty: 0.42,
        uploadSteps: 4,
      },
    });

    expect(bundle.passes.map((pass) => pass.id)).toEqual(
      TWIN_PSYCHE_THEOREM_PASSES
    );
    expect(TWIN_PSYCHE_THEOREMS.length).toBeGreaterThanOrEqual(105);
    expect(bundle.catalog).toHaveLength(TWIN_PSYCHE_THEOREMS.length);
    expect(
      bundle.catalog.some(
        (entry) => entry.id === 'THM-CONSCIOUSNESS-EQUALS-MIN-VOID-REJECTION'
      )
    ).toBe(true);
    expect(
      bundle.catalog.some(
        (entry) =>
          entry.id === 'THM-SHADOW-WALK-CONVERGES' &&
          entry.leanName === 'shadow_walk_converges' &&
          entry.leanSourcePath?.endsWith('PsycheGrind.lean') === true
      )
    ).toBe(true);
    expect(
      bundle.spotlight.some(
        (entry) => entry.theoremId === 'THM-OBSERVATION-CONVERGENCE'
      )
    ).toBe(true);
    expect(
      bundle.spotlight.some(
        (entry) => entry.theoremId === 'THM-OBSERVATION-CONVERGENCE'
      )
    ).toBe(true);
    expect(bundle.metrics.consciousnessWeight).toBeGreaterThan(0);
    expect(bundle.metrics.shadowIntegrity).toBeGreaterThan(0);
    expect(bundle.formalLedger.activeFamilies).toContain('voidWalking');
    expect(bundle.formalLedger.activeFamilies).toContain('community');
    expect(bundle.formalLedger.activeFamilies).toContain('metacognition');
    expect(bundle.formalLedger.activeFamilies).toContain('recovery');
    expect(bundle.formalLedger.compliance.status).toBe('declared');
  });

  test('emphasizes upload theorems on simulation surfaces', () => {
    const bundle = deriveTwinPsycheTheoremBundle({
      surface: 'simulation',
      subjectLabel: 'Continuity Test Rig',
      identity: {
        continuity: 0.72,
        distinctness: 0.71,
        observationDepth: 0.8,
      },
      psyche: {
        strainLoad: 0.47,
        dreamCadence: 0.69,
        breathCount: 2_048,
      },
      twin: {
        kind: 'synthetic',
        enabled: true,
        sessionActive: true,
        branchCount: 12,
        mergeNovelty: 0.7,
        serializationFidelity: 0.91,
        copyDistance: 0.11,
        uploadSteps: 7,
      },
    });

    expect(
      bundle.spotlight.some(
        (entry) => entry.theoremId === 'THM-UPLOAD-is-SERIALIZATION'
      )
    ).toBe(true);
    expect(
      bundle.spotlight.some(
        (entry) => entry.theoremId === 'THM-UPLOAD-CONTINUITY-GUARANTEE'
      )
    ).toBe(true);
    expect(bundle.metrics.voiceMultiplicity).toBeGreaterThan(0);
    expect(bundle.metrics.dreamRelief).toBeGreaterThan(0);
    expect(bundle.formalLedger.activeFamilies).toContain('voidWalking');
    expect(bundle.formalLedger.activeFamilies).toContain('negotiation');
    expect(bundle.formalLedger.activeFamilies).toContain('metacognition');
    expect(bundle.formalLedger.activeFamilies).toContain('recovery');
    expect(bundle.formalLedger.activeFamilies).toContain('probability');
  });
});
